import{_ as a,a as i,b as l}from"./chunks/支持留言.NiGCLVdp.js";import{_ as t,o as n,c as r,a2 as s}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Other/blog.md","filePath":"tr-TR/Other/blog.md","lastUpdated":1781962217000}'),o={name:"tr-TR/Other/blog.md"};function d(p,e,g,c,m,h){return n(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog özelliği ImgBed sitenize bağımsız bir blog sayfası ekler.</p><p>Etkinleştirildikten sonra ziyaretçiler şurayı açabilir:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+a+'" alt="Blog ana sayfası" loading="lazy"></p><p>Blog, açık kaynak <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a> projesinden uyarlanmıştır. ImgBed bunu Vue ile yeniden düzenleyip görsel barındırma sitesinin bir parçası olarak çalışacak şekilde entegre eder.</p><h2 id="nereden-yapılandırılır" tabindex="-1">Nereden Yapılandırılır? <a class="header-anchor" href="#nereden-yapılandırılır" aria-label="Permalink to &quot;Nereden Yapılandırılır?&quot;">​</a></h2><p>Blog ayarları şuradadır:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+i+'" alt="Blog ayarları" loading="lazy"></p><h2 id="ilk-kurulum" tabindex="-1">İlk Kurulum <a class="header-anchor" href="#ilk-kurulum" aria-label="Permalink to &quot;İlk Kurulum&quot;">​</a></h2><ol><li><code>Enable</code> değerini açın.</li><li>Blog yapılandırmasını saklamak için kullanılacak GitHub hesabını seçin.</li><li><code>Update Blog</code> düğmesine tıklayın.</li><li>Başarı mesajını bekleyin.</li><li>Blogu görmek için <code>https://your-domain.com/blog/</code> adresini açın.</li></ol><p>İlk kullanımda ImgBed seçilen hesap altında özel bir GitHub repository hazırlar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Bu repository blog ayarlarını ve yazı içeriklerini saklar.</p><h2 id="yazı-yazma" tabindex="-1">Yazı Yazma <a class="header-anchor" href="#yazı-yazma" aria-label="Permalink to &quot;Yazı Yazma&quot;">​</a></h2><p>Blog yazılarını özel GitHub repository&#39;niz içinde düzenleyin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Tipik iş akışı:</p><ol><li>GitHub&#39;ı açın.</li><li>Özel <code>imgbed-blog-config</code> repository&#39;sine girin.</li><li>Yazı dosyalarını düzenleyin veya yeni dosya ekleyin.</li><li>Değişiklikleri commit edin.</li><li>ImgBed yönetim paneline dönüp <code>Update Blog</code> düğmesine tıklayın veya blog ana sayfasının sol üst köşesindeki logoya üç kez tıklayarak blog güncellemesini tetikleyin.</li></ol><p><code>Update Blog</code> yazdığınız içeriğin üzerine yazmaz. Gerektiğinde repository&#39;yi başlatır ve blog önbelleğini yeniler.</p><h2 id="desteklenen-ozellikler" tabindex="-1">Desteklenen Özellikler <a class="header-anchor" href="#desteklenen-ozellikler" aria-label="Permalink to &quot;Desteklenen Özellikler&quot;">​</a></h2><p>Blog; yazı listesi, kategoriler, etiketler, arşiv, arama, karanlık mod ve dil değiştirme gibi yaygın blog özelliklerini destekler.</p><p>Ayrıca yorumlar ve ziyaret istatistikleri de desteklenir.</p><p><img src="'+l+'" alt="Blog yorumları" loading="lazy"></p><p>Yorumlar yazıların altında görünür. Ziyaretçiler avatar, nickname, email ve yorum içeriği gönderebilir.</p><p>Ziyaret istatistikleri yazı görüntülemelerini ve site ziyaretlerini gösterir; blog trafiğini anlamanıza yardımcı olur.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog her zaman <code>/blog/</code> altında sunulur.</p><p>Örneğin ImgBed alan adınız:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>Blog URL&#39;si:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Blog devre dışı bırakıldıktan sonra ziyaretçiler blog sayfasına erişemez.</p>',34)])])}const y=t(o,[["render",d]]);export{u as __pageData,y as default};
